// // This module is designed to decrement a 24-bit binary counter on each rising edge of the input clock (OSC_CLK_A). The two least significant bits of the counter control the states of two output LEDs (LED1 and LED2), providing a visual indication of the counter's lower bits. Additionally, the output signal CDONE_A is driven high when the input push-button (PB1) is pressed, effectively indicating an error or busy state by inverting the button's signal.
module top_module(
  input PB1,
  output LED1,
  output LED2,
  output CDONE_A,
  input OSC_CLK_A
);localparam bits = 24;
  reg [bits-1:0] counter = 0;

  always @(posedge OSC_CLK_A) begin
    counter <= counter + 1;
  end

  assign {LED1, LED2} = counter[bits-1:bits-2];
  assign CDONE_A = ~PB1;

endmodule
